def fake_sdk_call(model, **options):
    return {"model": model, **options}

def generate(prompt, **kwargs):
    # forward any extra options (temperature, max_tokens, ...) downstream
    return fake_sdk_call(model=kwargs.pop("model", "gpt-4o"), prompt=prompt, **kwargs)

print(generate("hi", temperature=0.2, max_tokens=64))

def get_weather(city: str) -> str:
    """Return a weather report for the given city."""
    return f"Sunny in {city}"

# A function is first-class: store it, look it up, call it.
TOOLS = {"get_weather": get_weather}

def run_tool(name, **args):
    return TOOLS[name](**args)

print(run_tool("get_weather", city="Paris"))   # Sunny in Paris

# Pass a function as a callback (e.g. to handle streamed tokens)
def stream(tokens, on_token):
    for t in tokens:
        on_token(t)

stream(["Gen", "AI"], print)
